/**
 * Represents a creative format with its requirements
 */
export interface Format {
  format_id: FormatReferenceStructuredObject;
  /**
   * Human-readable format name
   */
  name: string;
  /**
   * Plain text explanation of what this format does and what assets it requires
   */
  description?: string;
  /**
   * Optional URL to showcase page with examples and interactive demos of this format
   */
  example_url?: string;
  /**
   * List of parameters this format accepts in format_id. Template formats define which parameters (dimensions, duration, etc.) can be specified when instantiating the format. Empty or omitted means this is a concrete format with fixed parameters.
   */
  accepts_parameters?: FormatIDParameter[];
  /**
   * Specification of rendered pieces for this format. Most formats produce a single render. Companion ad formats (video + banner), adaptive formats, and multi-placement formats produce multiple renders. Each render specifies its role and dimensions.
   */
  renders?: (
    | {
        /**
         * Semantic role of this rendered piece (e.g., 'primary', 'companion', 'mobile_variant')
         */
        role: string;
        /**
         * Dimensions for this rendered piece. Defaults to pixels when unit is absent.
         */
        dimensions: {
          /**
           * Fixed width. Interpretation depends on unit (default: pixels).
           */
          width?: number;
          /**
           * Fixed height. Interpretation depends on unit (default: pixels).
           */
          height?: number;
          /**
           * Minimum width for responsive renders
           */
          min_width?: number;
          /**
           * Minimum height for responsive renders
           */
          min_height?: number;
          /**
           * Maximum width for responsive renders
           */
          max_width?: number;
          /**
           * Maximum height for responsive renders
           */
          max_height?: number;
          unit?: DimensionUnit;
          /**
           * Indicates which dimensions are responsive/fluid
           */
          responsive?: {
            width: boolean;
            height: boolean;
          };
          /**
           * Fixed aspect ratio constraint (e.g., '16:9', '4:3', '1:1', '1.91:1')
           * @pattern ^\d+(\.\d+)?:\d+(\.\d+)?$
           */
          aspect_ratio?: string;
        };
      }
    | {
        /**
         * Semantic role of this rendered piece (e.g., 'primary', 'companion', 'mobile_variant')
         */
        role: string;
        parameters_from_format_id: true;
      }
  )[];
  /**
   * Array of all assets supported for this format. Each asset is identified by its asset_id, which must be used as the key in creative manifests. Use the 'required' boolean on each asset to indicate whether it's mandatory.
   */
  assets?: FormatAssetSlot[];
  /**
   * Delivery method specifications (e.g., hosted, VAST, third-party tags)
   */
  delivery?: {};
  /**
   * List of universal macros supported by this format (e.g., MEDIA_BUY_ID, CACHEBUSTER, DEVICE_ID). Used for validation and developer tooling. See docs/creative/universal-macros.mdx for full documentation.
   */
  supported_macros?: (UniversalMacro | string)[];
  /**
   * Array of format IDs this format accepts as input creative manifests. When present, indicates this format can take existing creatives in these formats as input. Omit for formats that work from raw assets (images, text, etc.) rather than existing creatives.
   */
  input_format_ids?: FormatReferenceStructuredObject[];
  /**
   * Array of format IDs that this format can produce as output. When present, indicates this format can build creatives in these output formats (e.g., a multi-publisher template format might produce standard display formats across many publishers). Omit for formats that produce a single fixed output (the format itself).
   */
  output_format_ids?: FormatReferenceStructuredObject[];
  /**
   * Optional standard visual card (300x400px) for displaying this format in user interfaces. Can be rendered via preview_creative or pre-generated.
   */
  format_card?: {
    format_id: FormatReferenceStructuredObject;
    /**
     * Asset manifest for rendering the card, structure defined by the format
     */
    manifest: {};
  };
  /**
   * Accessibility posture of this format. Declares the WCAG conformance level that creatives produced by this format will meet.
   */
  accessibility?: {
    wcag_level: WCAGLevel;
    /**
     * When true, all assets with x-accessibility fields must include those fields. For inspectable assets (image, video, audio), this means providing accessibility metadata like alt_text or captions. For opaque assets (HTML, JavaScript), this means providing self-declared accessibility properties.
     */
    requires_accessible_assets?: boolean;
  };
  /**
   * Disclosure positions this format can render. Buyers use this to determine whether a format can satisfy their compliance requirements before submitting a creative. When omitted, the format makes no disclosure rendering guarantees — creative agents SHOULD treat this as incompatible with briefs that require specific disclosure positions. Values correspond to positions on creative-brief.json required_disclosures.
   */
  supported_disclosure_positions?: DisclosurePosition[];
  /**
   * Structured disclosure capabilities per position with persistence modes. Declares which persistence behaviors each disclosure position supports, enabling persistence-aware matching against provenance render guidance and brief requirements. When present, supersedes supported_disclosure_positions for persistence-aware queries. The flat supported_disclosure_positions field is retained for backward compatibility. Each position MUST appear at most once; validators and agents SHOULD reject duplicates.
   */
  disclosure_capabilities?: {
    position: DisclosurePosition;
    /**
     * Persistence modes this position supports
     */
    persistence: DisclosurePersistence[];
  }[];
  /**
   * Optional detailed card with carousel and full specifications. Provides rich format documentation similar to ad spec pages.
   */
  format_card_detailed?: {
    format_id: FormatReferenceStructuredObject;
    /**
     * Asset manifest for rendering the detailed card, structure defined by the format
     */
    manifest: {};
  };
  /**
   * Metrics this format can produce in delivery reporting. Buyers receive the intersection of format reported_metrics and product available_metrics. If omitted, the format defers entirely to product-level metric declarations.
   */
  reported_metrics?: AvailableMetric[];
  /**
   * Pricing options for this format. Used by transformation and generation agents that charge per format adapted, per image generated, or per unit of work. Present when the request included include_pricing=true and account. Ad servers and library-based agents expose pricing on list_creatives instead.
   */
  pricing_options?: VendorPricingOption[];
  canonical?: CanonicalProjectionReference;
  canonical_parameters?: ProductFormatDeclaration;
}
export interface BaseIndividualAsset {
  /**
   * Discriminator indicating this is an individual asset
   */
  item_type: 'individual';
  /**
   * Unique identifier for this asset. Creative manifests MUST use this exact value as the key in the assets object.
   */
  asset_id: string;
  /**
   * Descriptive label for this asset's purpose (e.g., 'hero_image', 'logo', 'third_party_tracking'). For documentation and UI display only — manifests key assets by asset_id, not asset_role.
   */
  asset_role?: string;
  /**
   * Whether this asset is required (true) or optional (false). Required assets must be provided for a valid creative. Optional assets enhance the creative but are not mandatory.
   */
  required: boolean;
  /**
   * Publisher-controlled elements rendered on top of buyer content at this asset's position (e.g., video player controls, publisher logos). Creative agents should avoid placing critical content (CTAs, logos, key copy) within overlay bounds.
   */
  overlays?: Overlay[];
  /**
   * Optional canonical asset_group_id this slot fills, drawn from /schemas/core/asset-group-vocabulary.json. Lets buyers and migration tools resolve v1 author-invented slot names (e.g., `click_url`) to canonical names (e.g., `landing_page_url`). Validators MAY soft-warn when a v1 slot's asset_id is a known alias but no asset_group_id is declared.
   */
  asset_group_id?: string;
}
/**
 * A publisher-controlled element that renders on top of buyer creative content within the ad placement. Creative agents should avoid placing critical content (CTAs, logos, key copy) within overlay bounds.
 */
export interface Overlay {
  /**
   * Identifier for this overlay (e.g., 'play_pause', 'volume', 'publisher_logo', 'carousel_prev', 'carousel_next')
   */
  id: string;
  /**
   * Human-readable explanation of what this overlay is and how buyers should account for it
   */
  description?: string;
  /**
   * Optional visual reference for this overlay element. Useful for creative agents compositing previews and for buyers understanding what will appear over their content. Must include at least one of: url, light, or dark.
   */
  visual?: {
    /**
     * URL to a theme-neutral overlay graphic (SVG or PNG). Use when a single file works for all backgrounds, e.g. an SVG using CSS custom properties or currentColor.
     */
    url?: string;
    /**
     * URL to the overlay graphic for use on light/bright backgrounds (SVG or PNG)
     */
    light?: string;
    /**
     * URL to the overlay graphic for use on dark backgrounds (SVG or PNG)
     */
    dark?: string;
  };
  /**
   * Position and size of the overlay relative to the asset's own top-left corner. See 'unit' for coordinate interpretation.
   */
  bounds: {
    /**
     * Horizontal offset from the asset's left edge
     */
    x: number;
    /**
     * Vertical offset from the asset's top edge
     */
    y: number;
    /**
     * Width of the overlay
     * @minimum 0
     */
    width: number;
    /**
     * Height of the overlay
     * @minimum 0
     */
    height: number;
    /**
     * 'px' = absolute pixels from asset top-left. 'fraction' = proportional to asset dimensions (0.0 = edge, 1.0 = opposite edge). 'inches', 'cm', 'mm', 'pt' (1/72 inch) = physical units for print overlays, measured from asset top-left.
     */
    unit: 'px' | 'fraction' | 'inches' | 'cm' | 'mm' | 'pt';
  };
}
/**
 * Repeatable asset group (for carousels, slideshows, playlists, etc.)
 */
export interface RepeatableGroupAsset {
  /**
   * Discriminator indicating this is a repeatable asset group
   */
  item_type: 'repeatable_group';
  /**
   * Identifier for this asset group (e.g., 'product', 'slide', 'card')
   */
  asset_group_id: string;
  /**
   * Whether this asset group is required. If true, at least min_count repetitions must be provided.
   */
  required: boolean;
  /**
   * Minimum number of repetitions required (if group is required) or allowed (if optional)
   * @minimum 0
   */
  min_count: number;
  /**
   * Maximum number of repetitions allowed
   * @minimum 1
   */
  max_count: number;
  /**
   * How the platform uses repetitions of this group. 'sequential' means all items display in order (carousels, playlists). 'optimize' means the platform selects the best-performing combination from alternatives (asset group optimization like Meta Advantage+ or Google Pmax).
   */
  selection_mode?: 'sequential' | 'optimize';
  /**
   * Assets within each repetition of this group
   */
  assets: GroupAssetSlot[];
}
export interface BaseGroupAsset {
  /**
   * Identifier for this asset within the group
   */
  asset_id: string;
  /**
   * Descriptive label for this asset's purpose. For documentation and UI display only — manifests key assets by asset_id, not asset_role.
   */
  asset_role?: string;
  /**
   * Optional canonical asset_group_id this slot fills, drawn from /schemas/core/asset-group-vocabulary.json. Same semantics as on baseIndividualAsset — lets buyers and migration tools resolve v1 author-invented slot names to canonical names.
   */
  asset_group_id?: string;
  /**
   * Whether this asset is required within each repetition of the group
   */
  required: boolean;
  /**
   * Publisher-controlled elements rendered on top of buyer content at this asset's position (e.g., carousel navigation arrows, slide indicators). Creative agents should avoid placing critical content within overlay bounds.
   */
  overlays?: Overlay[];
}

// core/hotel-item.json
/**
 * A hotel or lodging property within a hotel-type catalog. Carries the property data that platforms use for hotel ads, dynamic remarketing, and travel campaign creatives. Maps to Google Hotel Center feeds, Meta hotel catalogs, and similar platform-native formats.
 */
export interface HotelItem {
  /**
   * Unique identifier for this property. Used to match remarketing events and inventory feeds to the correct hotel.
   */
  hotel_id: string;
  /**
   * Property name (e.g., 'Grand Hotel Amsterdam', 'Seaside Resort & Spa').
   */
  name: string;
  /**
   * Property description highlighting features and location.
   */
  description?: string;
  /**
   * Geographic coordinates of the property.
   */
  location: {
    /**
     * Latitude in decimal degrees (WGS 84).
     * @minimum -90
     * @maximum 90
     */
    lat: number;
    /**
     * Longitude in decimal degrees (WGS 84).
     * @minimum -180
     * @maximum 180
     */
    lng: number;
  };
  /**
   * Structured address for display and geocoding.
   */
  address?: {
    /**
     * Street address.
     */
    street?: string;
    /**
     * City name.
     */
    city?: string;
    /**
     * State, province, or region.
     */
    region?: string;
    /**
     * Postal or ZIP code.
     */
    postal_code?: string;
    /**
     * ISO 3166-1 alpha-2 country code.
     * @pattern ^[A-Z]{2}$
     */
    country?: string;
  };
  /**
   * Official star rating (1–5).
   * @minimum 1
   * @maximum 5
   */
  star_rating?: number;
  price?: Price;
  /**
   * Primary property image URL.
   */
  image_url?: string;
  /**
   * Property landing page or booking URL.
   */
  url?: string;
  /**
   * Property phone number in E.164 format.
   */
  phone?: string;
  /**
   * Property amenities (e.g., 'pool', 'wifi', 'spa', 'parking', 'restaurant').
   */
  amenities?: string[];
  /**
   * Standard check-in time in HH:MM format (e.g., '15:00').
   * @pattern ^[0-2][0-9]:[0-5][0-9]$
   */
  check_in_time?: string;
  /**
   * Standard check-out time in HH:MM format (e.g., '11:00').
   * @pattern ^[0-2][0-9]:[0-5][0-9]$
   */
  check_out_time?: string;
  /**
   * Tags for filtering and targeting (e.g., 'boutique', 'family', 'business', 'luxury').
   */
  tags?: string[];
  /**
   * Date from which this item is available or this rate applies (ISO 8601, e.g., '2025-03-01'). Used for seasonal availability windows in feed imports.
   * @format date
   */
  valid_from?: string;
  /**
   * Date until which this item is available or this rate applies (ISO 8601, e.g., '2025-09-30'). Used for seasonal availability windows in feed imports.
   * @format date
   */
  valid_to?: string;
  /**
   * Typed creative asset pools for this hotel. Uses the same OfferingAssetGroup structure as offering-type catalogs. Standard group IDs: 'images_landscape' (16:9 hero images), 'images_vertical' (9:16 for Snap, Stories), 'images_square' (1:1), 'logo'. Enables formats to declare typed image requirements that map unambiguously to the right asset regardless of platform.
   */
  assets?: OfferingAssetGroup[];
  ext?: ExtensionObject;
}

// core/job-item.json
/**
 * A job posting within a job-type catalog. Carries the position details that platforms use for job ads and recruitment campaigns. Maps to LinkedIn Jobs XML, Google DynamicJobsAsset, schema.org JobPosting, and similar formats.
 */
export interface JobItem {
  /**
   * Unique identifier for this job posting.
   */
  job_id: string;
  /**
   * Job title (e.g., 'Senior Software Engineer', 'Marketing Manager').
   */
  title: string;
  /**
   * Hiring company or organization name.
   */
  company_name: string;
  /**
   * Full job description including responsibilities and qualifications.
   */
  description: string;
  /**
   * Job location as a display string (e.g., 'Amsterdam, NL', 'Remote', 'New York, NY'). Use 'Remote' for fully remote positions.
   */
  location?: string;
  /**
   * Type of employment.
   */
  employment_type?: 'full_time' | 'part_time' | 'contract' | 'temporary' | 'internship' | 'freelance';
  /**
   * Required experience level.
   */
  experience_level?: 'entry_level' | 'mid_level' | 'senior' | 'director' | 'executive';
  /**
   * Salary range. Specify min and/or max with currency and period.
   */
  salary?: {
    /**
     * Minimum salary.
     * @minimum 0
     */
    min?: number;
    /**
     * Maximum salary.
     * @minimum 0
     */
    max?: number;
    /**
     * ISO 4217 currency code.
     * @pattern ^[A-Z]{3}$
     */
    currency: string;
    /**
     * Pay period.
     */
    period: 'hour' | 'month' | 'year';
  };
  /**
   * Date the job was posted (ISO 8601 date).
   * @format date
   */
  date_posted?: string;
  /**
   * Application deadline (ISO 8601 date).
   * @format date
   */
  valid_through?: string;
  /**
   * Direct application URL.
   */
  apply_url?: string;
  /**
   * Job function categories (e.g., 'engineering', 'marketing', 'sales', 'finance').
   */
  job_functions?: string[];
  /**
   * Industry classifications (e.g., 'technology', 'healthcare', 'retail').
   */
  industries?: string[];
  /**
   * Tags for filtering (e.g., 'remote', 'visa-sponsorship', 'equity').
   */
  tags?: string[];
  /**
   * Typed creative asset pools for this job. Uses the same OfferingAssetGroup structure as offering-type catalogs. Standard group IDs: 'images_landscape' (company/role hero), 'images_vertical' (9:16 for Stories), 'logo' (company logo). Enables formats to declare typed image requirements that map unambiguously to the right asset regardless of platform.
   */
  assets?: OfferingAssetGroup[];
  ext?: ExtensionObject;
}

// core/offering.json
/**
 * A promotable offering from a brand. Can represent a campaign, product promotion, service, or any other thing the brand wants to make available. Offerings carry structured asset groups for creative assembly and can be promoted via traditional creatives or conversational SI experiences (via the brand's SI agent).
 */
export interface Offering {
  /**
   * Unique identifier for this offering. Used by hosts to reference specific offerings in si_get_offering calls.
   */
  offering_id: string;
  /**
   * Human-readable offering name (e.g., 'Winter Sale', 'Free Trial', 'Enterprise Platform')
   */
  name: string;
  /**
   * Description of what's being offered
   */
  description?: string;
  /**
   * Short promotional tagline for the offering
   */
  tagline?: string;
  /**
   * When the offering becomes available. If not specified, offering is immediately available.
   * @format date-time
   */
  valid_from?: string;
  /**
   * When the offering expires. If not specified, offering has no expiration.
   * @format date-time
   */
  valid_to?: string;
  /**
   * URL for checkout/purchase flow when the brand doesn't support agentic checkout.
   */
  checkout_url?: string;
  /**
   * Landing page URL for this offering. For catalog-driven creatives, this is the per-item click-through destination that platforms map to the ad's link-out URL. Every offering in a catalog should have a landing_url unless the format provides its own destination logic.
   */
  landing_url?: string;
  /**
   * Structured asset groups for this offering. Each group carries a typed pool of creative assets (headlines, images, videos, etc.) identified by a group ID that matches format-level vocabulary.
   */
  assets?: OfferingAssetGroup[];
  /**
   * Geographic scope of this offering. Declares where the offering is relevant — for location-specific offerings such as job vacancies, in-store promotions, or local events. Platforms use this to target geographically appropriate audiences and to filter out offerings irrelevant to a user's location. Uses the same geographic structures as targeting_overlay in create_media_buy.
   */
  geo_targets?: {
    /**
     * Countries where this offering is relevant. ISO 3166-1 alpha-2 codes (e.g., 'US', 'NL', 'DE').
     */
    countries?: string[];
    /**
     * Regions or states where this offering is relevant. ISO 3166-2 subdivision codes (e.g., 'NL-NH', 'US-CA').
     */
    regions?: string[];
    /**
     * Metro areas where this offering is relevant. Each entry specifies the classification system and target values.
     */
    metros?: {
      system: MetroAreaSystem;
      /**
       * Metro codes within the system
       */
      values: string[];
    }[];
    /**
     * Postal areas where this offering is relevant. Each entry specifies the postal system and target values.
     */
    postal_areas?: {
      system: PostalCodeSystem;
      /**
       * Postal codes within the system
       */
      values: string[];
    }[];
  };
  /**
   * Keywords for matching this offering to user intent. Hosts use these for retrieval/relevance scoring.
   */
  keywords?: string[];
  /**
   * Categories this offering belongs to (e.g., 'measurement', 'identity', 'programmatic')
   */
  categories?: string[];
  ext?: ExtensionObject;
}

// core/performance-feedback.json
/**
 * Represents performance feedback data for a media buy or package
 */
export interface PerformanceFeedback {
  /**
   * Unique identifier for this performance feedback submission
   */
  feedback_id: string;
  /**
   * Publisher's media buy identifier
   */
  media_buy_id: string;
  /**
   * Specific package within the media buy (if feedback is package-specific)
   */
  package_id?: string;
  /**
   * Specific creative asset (if feedback is creative-specific)
   */
  creative_id?: string;
  /**
   * Time period for performance measurement
   */
  measurement_period: {
    /**
     * ISO 8601 start timestamp for measurement period
     * @format date-time
     */
    start: string;
    /**
     * ISO 8601 end timestamp for measurement period
     * @format date-time
     */
    end: string;
  };
  /**
   * Normalized performance score (0.0 = no value, 1.0 = expected, >1.0 = above expected)
   * @minimum 0
   */
  performance_index: number;
  metric_type?: MetricTypeDeprecated;
  /**
   * The metric this feedback row pertains to, using the same `(scope, metric_id, qualifier)` row shape as `committed_metrics` and `metric_aggregates`. Preferred over the legacy `metric_type` field for new implementations. Brings performance-feedback into the same atomic unit and dispatch model as the rest of the measurement surface — buyer agents reconcile feedback against the contract surface using the row-level join on `(scope, metric_id, qualifier)`. **Optional and may be omitted entirely for holistic feedback** (e.g., a trader flagging a campaign as underperforming without a specific metric in mind — `performance_index` plus the response narrative carry the signal). Senders SHOULD populate `metric` when the feedback is metric-specific so consumers can route it to the right optimization path; senders MAY omit it for general performance feedback.
   */
  metric?:
    | {
        /**
         * Standard metric from the closed `available-metric.json` enum.
         */
        scope: 'standard';
        metric_id: AvailableMetric;
        /**
         * Disambiguator — same shape as `committed_metrics.qualifier`. Carry `viewability_standard` for MRC vs GroupM viewability feedback; `completion_source` for seller- vs vendor-attested completion feedback; `attribution_methodology` and `attribution_window` for outcome-metric feedback (the buyer pinning a specific methodology or window when the feedback is methodology-sensitive). Closed (`additionalProperties: false`); new keys ship explicitly in subsequent minors.
         */
        qualifier?: {
          viewability_standard?: ViewabilityStandard;
          completion_source?: CompletionSource;
          attribution_methodology?: AttributionMethodology;
          attribution_window?: Duration;
          lift_dimension?: LiftDimension;
        };
      }
    | {
        /**
         * Vendor-defined metric, identified by the tuple `(vendor, metric_id)`.
         */
        scope: 'vendor';
        vendor: BrandReference;
        metric_id: VendorMetricID;
      };
  feedback_source: FeedbackSource;
  vendor?: BrandReference;
  /**
   * Processing status of the performance feedback
   */
  status: 'accepted' | 'queued' | 'applied' | 'rejected';
  /**
   * ISO 8601 timestamp when feedback was submitted
   * @format date-time
   */
  submitted_at: string;
  /**
   * ISO 8601 timestamp when feedback was applied to optimization algorithms
   * @format date-time
   */
  applied_at?: string;
}

// core/placement-definition.json
/**
 * Canonical placement definition published in a publisher's adagents.json. Defines stable placement IDs that products can reuse and that authorization rules can reference. When a product reuses a registered placement_id, it is referring to this same semantic placement, not inventing a new one with the same ID.
 */
export type PlacementDefinition = {
  [k: string]: unknown | undefined;
} & {
  /**
   * Stable placement identifier unique within this adagents.json file.
   */
  placement_id: string;
  /**
   * Human-readable placement name (e.g., 'Homepage Banner', 'Pre-roll', 'Sponsored Listing Slot 1').
   */
  name: string;
  /**
   * Description of where and how this placement appears.
   */
  description?: string;
  /**
   * Tags for grouping and querying placements across properties and products (e.g., 'homepage', 'native', 'premium', 'pre_roll').
   */
  tags?: string[];
  /**
   * Property IDs in this adagents.json where this placement can appear.
   */
  property_ids?: PropertyID[];
  /**
   * Property tags in this adagents.json where this placement can appear. Useful for network-wide positions such as 'pre_roll' or 'homepage_native_feed'.
   */
  property_tags?: PropertyTag[];
  /**
   * Optional collection IDs in this adagents.json where this placement is valid. Use to narrow a placement to specific content programs carried on the selected properties.
   */
  collection_ids?: string[];
  /**
   * Advertising channels where this placement can run. Products that reference the placement may narrow this set but should not broaden it.
   */
  channels?: MediaChannel[];
  /**
   * Optional 3.1+ canonical format-option declarations supported by this placement. Two ways to populate an entry: (1) reference an entry in the file's top-level `formats[]` by `format_option_id` only — buyers resolve the full declaration from `formats[]` by matching `format_option_id` (recommended; avoids duplication). Top-level formats may be publisher-owned custom formats or narrowed canonical formats; their `format_kind` is the canonical anchor that the placement reference inherits. (2) carry an inline `ProductFormatDeclaration` directly — for placement-specific canonical narrowing that doesn't fit a reusable catalog entry. Same anyOf pattern as Product.
   *
   * Product-level formats remain the upper bound for a sellable product. Catalog placement formats describe placement support; when a product references the placement and also declares product-level formats, buyers use the intersection for that product placement. A catalog placement format that is absent from the product-level declaration is not accepted for that product unless the product explicitly includes it.
   *
   * **Format-option reference shape.** A format-option reference entry SHOULD carry ONLY `format_option_id` — extra fields are allowed (`additionalProperties: true`) so adopters who want to attach a placement-local override like `display_name` don't get rejected by the branch boundary, but buyer SDKs MUST resolve the format from the top-level `formats[]` by `format_option_id` and apply additional fields on the entry as placement-level overrides (NOT as a partial inline declaration). If a publisher needs to materially narrow the format at the placement, use the inline-declaration form instead.
   *
   * **Resolution scope is same-file only.** `format_option_id` resolves only within this file's top-level `formats[]`; cross-file references are not supported by design because same-file resolution keeps validation bounded and prevents a file from squatting on or narrowing another publisher's format_option_id. When `format_options[]` references a `format_option_id` not declared in the file's top-level `formats[]`, validators MUST surface this as `FORMAT_OPTION_UNRESOLVED` on the response `errors[]`. Buyers MUST fail closed for that placement (drop the format from the placement's accepted set) rather than silently dropping the placement or guessing intent.
   */
  format_options?: (FormatOptionReference | InlineDeclaration)[];
  ext?: ExtensionObject;
};
/**
 * Inline 3.1+ canonical format-option declaration. Use when the placement narrows a format in a way that's not worth a top-level catalog entry.
 */
export type InlineDeclaration = {
  [k: string]: unknown | undefined;
} & {
  /**
   * Stable identifier for this format declaration within its namespace. REQUIRED when the parent product's `format_options` contains multiple declarations sharing the same `format_kind` (so buyers can disambiguate which option a manifest targets via `manifest.format_option_ref`). SHOULD be set on EVERY `format_options[]` entry — not just when structurally required to break a `format_kind` collision — so V2-mental-model buyers can use the V2 authoring path (`PackageRequest.format_option_refs[]`, `creative-manifest.format_option_ref`) against the product. Publisher-catalog-backed options pair this with `publisher_domain`; product-local options omit `publisher_domain` and are selected by `format_option_id` within the target product. A product that ships without selectable `format_option_id` values on its `format_options[]` entries is structurally 3.1-conformant but is not V2-authorable: buyers fall back to v1 `format_ids[]` and lose the stable naming the V2 path was designed to provide. Sellers MUST reject V2 authoring against such products with `UNSUPPORTED_FEATURE` and `error.details.reason` set to `format_option_refs_not_published` per `package-request.json`. Format-internal (not a URI). Examples: 'display_image_300x250', 'responsive_search', 'daily_pulse_homepage_image'.
   */
  format_option_id?: string;
  /**
   * Namespace for `format_option_id` when this declaration references or narrows a publisher-declared format option from that publisher's adagents.json top-level `formats[]`. Product-local options omit this field and are selected by `format_option_id` within the target product.
   * @pattern ^[a-z0-9]([a-z0-9-]*[a-z0-9])?(\.[a-z0-9]([a-z0-9-]*[a-z0-9])?)*$
   */
  publisher_domain?: string;
  /**
   * Optional seller-controlled human-readable label for this format declaration. Used by buyer dashboards, catalog UIs, and reporting surfaces to show a seller's own naming ('Homepage Takeover', 'Branded Canvas', 'Reels Premium Video') rather than the raw `format_kind` or `format_option_id`. Has no machine semantics — buyer agents route on `format_kind` and `format_option_id`; `display_name` is purely for human presentation. Freeform; no enumeration. Sellers SHOULD keep it stable once published to avoid dashboard churn.
   */
  display_name?: string;
  /**
   * Optional subset of the parent product's `channels` to which this declaration applies. When omitted, the declaration applies to ALL channels declared on the product. Lets a multi-channel product (e.g., `channels: ['display', 'video']`) carry distinct format_options per channel — `format_options: [{format_kind: 'image', applies_to_channels: ['display']}, {format_kind: 'video_hosted', applies_to_channels: ['video']}]`. Buyers ship channel-appropriate manifests per `applies_to_channels`.
   */
  applies_to_channels?: MediaChannel[];
  /**
   * Optional soft routing hint *within* a product's accepted set of formats — NOT an enforcement axis. `preferred` — seller actively recommends this format (often because of measurement, viewability, or render-quality differences); `accepted` — supported on equal footing with other format_options (default when omitted); `discouraged` — supported but suboptimal (e.g., legacy 3p-tag where the seller would prefer html5 for OM-SDK coverage). Buyer agents picking between format_options SHOULD respect seller preferences when their own constraints don't override.
   *
   * **Not an enforcement axis (normative).** `seller_preference` does NOT carry the meaning of 'this format won't work / required-only'. That case is structural: `format_options[]` IS the closed set of accepted formats; anything outside the list is rejected at `create_media_buy` regardless of preference. A seller that accepts only one format lists exactly that one entry — the structural fact does the enforcement work, no enum value needed. There is intentionally no `required` value; preference is bounded to *ranking within the already-accepted set*, not gating into it.
   */
  seller_preference?: 'preferred' | 'accepted' | 'discouraged';
  /**
   * When true, this format declaration has no clean v1 projection and SDKs MUST NOT synthesize a v1 `format_id` for it. Buyers reading the product on the v1 wire path see this declaration absent from `format_ids`; only v2-aware buyers (reading `format_options`) discover it. Set explicitly for `format_kind: "custom"` declarations (no canonical exists in v1 to project onto) and for declarations whose canonical/parameter shape cannot round-trip through a v1 named format without semantic loss. The protocol does NOT mint synthetic v1 format_ids for unmappable declarations — the alternative (an `aao-synth/*` namespace populated automatically) was considered and rejected because adopters would index on synthetic IDs that have no stable identity. Producers SHOULD set `canonical_formats_only: true` rather than omit the declaration from `format_options` — explicit v2-only is more useful than silent absence.
   */
  canonical_formats_only?: boolean;
  /**
   * When true, THIS seller's specific product declaration may not work as declared — even if the underlying canonical is stable. Use for beta runtime paths, forward-looking catalog entries the runtime doesn't yet honor, or experimental products where the seller wants buyer-side caution. Buyers reading `experimental: true` on a product declaration SHOULD prefer the legacy named-format path when a fallback exists for the same product (via `format_ids` on the parent product or via this declaration's `v1_format_ref`) and SHOULD validate via `validate_input` or a sandbox before routing production budget.
   *
   * Independent of the canonical's own `experimental` flag — a stable canonical (e.g., `image`, `video_hosted`) can carry an experimental product declaration when the seller is shipping a new runtime path that isn't fully wired yet. Conversely, an experimental canonical (`sponsored_placement`, `responsive_creative`, `agent_placement`) MAY carry non-experimental product declarations where the seller's adopter contract is well-tested. Buyer SDKs SHOULD filter products with `experimental: true` from default views and offer an opt-in flag to surface them.
   *
   * Replaces the earlier `runtime_status` enum (`stable | preview | declared_only`) — same semantic ('use with caution') without the cognitive overhead of two stability axes.
   */
  experimental?: boolean;
  /**
   * REQUIRED when `format_kind: "custom"`; otherwise MUST be absent. Recognized global pattern this custom shape is an instance of, drawn from the [format-shape vocabulary registry](/schemas/core/format-shape-vocabulary.json) (`multi_placement_takeover`, `roadblock`, `branded_content`, `cross_screen_sponsorship`, `sponsorship_lockup`, `newsletter_sponsorship`, `ar_lens`, `playable`, `live_event_sponsorship`, …). Non-canonical values valid (validators MAY soft-warn) — adopters CAN ship a shape that isn't yet in the registry. Adding entries is a vocabulary PR. Once a `format_shape` entry sees 2+ adopters with substantively similar `format_schema` content for 90+ days, the working group promotes it to a first-class canonical.
   */
  format_shape?: string;
  /**
   * Authoritative v2 → v1 link, expressed as an array of one or more v1 `format_id` ({agent_url, id}) values. Each entry asserts that this canonical-formats declaration IS the same underlying format as the referenced v1 named format. Always an array (single-ref is `[{...}]`) so the multi-size case below has a clean wire shape — adopters surveyed in the SDK implementor review pushed for this over the lossy single-ref form.
   *
   * The v2 declaration's `params` MUST narrow (be compatible with) each referenced v1 format's `requirements` — see the 'Narrows — formal definition' section in canonical-formats.mdx. SDKs comparing dual-emitted shapes (`Product.format_ids[]` ⊇ entries from `v1_format_ref` AND `Product.format_options[]` carrying this declaration) treat the link as the authoritative pairing and run the narrowing check between this declaration and EACH referenced v1 format file's `requirements`.
   *
   * **Multi-size fan-out (normative).** When the declaration carries `params.sizes: [{w,h}, ...]` (multi-size flexible slot), sellers SHOULD carry one `v1_format_ref[]` entry per size, each pointing at the per-size v1 named format in the AAO catalog. Example: a multi-size image declaration with `sizes: [300x250, 728x90, 970x250]` SHOULD carry `v1_format_ref: [{aao, display_300x250_image}, {aao, display_728x90_image}, {aao, display_970x250_image}]`. v1-only buyers then see the product on all three sizes via the `format_ids[]` dual-emission. When `v1_format_ref[]` count < `sizes[]` count, SDKs MUST emit `FORMAT_DECLARATION_V1_LOSSY_MULTI_SIZE` on the response `errors[]` (advisory, alongside the partial-coverage v1 emit — NOT in place of it). SDKs MAY (non-normative) fan out automatically by catalog lookup when `v1_format_ref[]` has length 1 and `sizes[]` has length N — opt-in, requires catalog access; sellers asserting refs is the source of truth.
   *
   * Mutually exclusive with `canonical_formats_only: true` — a declaration can EITHER assert no v1 projection (`canonical_formats_only: true`) OR link to v1 named formats (`v1_format_ref[]`), never both. When neither is present, SDKs fall back to the resolution order in `v1-canonical-mapping.json` (seller's explicit `canonical` field on the v1 file → registry glob → structural match → fail-closed).
   *
   * This is the v2-side authoritative replacement for the v1-side `canonical_parameters` field on `format.json` (which is deprecated for 3.1, removed at 4.0). Sellers SHOULD prefer authoring v2 declarations with `v1_format_ref[]` over mirroring the v2 shape onto v1 files via `canonical_parameters`; the directional link (v2 declaration → v1 identifiers) is the same fact without the parallel-shape drift surface.
   *
   * **AAO-hosted convention (normative).** For IAB-standard formats (image dimensions, VAST/DAAST tags, standard third-party tags, HTML5 banner bundles), sellers SHOULD point each `v1_format_ref[].agent_url` at the AAO-hosted canonical agent URL `https://creative.adcontextprotocol.org` and use the registry-published id (e.g., `display_300x250_image`, `video_vast_30s`, `audio_standard_30s`, `display_300x250_html`, `display_js`). This converges the v1-wire namespace: every seller's IAB MREC points at the same `{agent_url, id}` pair, so v1-only buyers' allowlists work uniformly. Without this convention, every publisher's 300x250 ships with a different `v1_format_ref` (theirs vs nytimes.example vs cnn.example vs …) and the v1 wire fragments into per-publisher namespaces — exactly what canonical-formats was designed to eliminate.
   *
   * For platform-specific formats (Meta Reels, TikTok Spark, Snap Spotlight, etc.), each `v1_format_ref[].agent_url` SHOULD point at the platform's own agent_url when the platform has adopted AdCP and publishes its own `adagents.json` with `formats[]`. When the platform has NOT adopted AdCP, sellers SHOULD point at the AAO community-registry mirror — `https://creative.adcontextprotocol.org/translated/<platform>` + `id: <platform-format-name>` (e.g., `https://creative.adcontextprotocol.org/translated/meta` + `id: meta_reels`). This keeps the v1 namespace converged across all sellers selling that platform's inventory until the platform owns its own adagents.json.
   *
   * **Platform-adoption cutover (normative).** When a platform adopts AdCP and publishes its own adagents.json, sellers MUST update `v1_format_ref[].agent_url` to the platform's adopted agent_url in the same minor release as the AAO mirror entry's `superseded_by` field goes live (see `static/schemas/source/adagents.json#superseded_by`). The AAO mirror entry SHOULD continue serving for ≥1 minor release after `superseded_by` is set, returning an advisory 'superseded' marker so v1 buyer allowlists keyed on the mirror URL get an explicit signal rather than a silent break. **Identity-confusion note**: the mirror URL is *format-shape namespace*, NOT seller identity. Inventory authorization always flows from `authorized_agents[]` + publisher signing keys; a buyer matching `v1_format_ref[].agent_url` against an allowlist is matching format-shape provenance, not seller identity.
   *
   * **Mirror domain migration (3.1).** Earlier drafts used `https://mirror.adcontextprotocol.org/translated/<platform>`. As of this release, the convention is `https://creative.adcontextprotocol.org/translated/<platform>` — sibling content under the AAO catalog domain we already host. Adopters who hardcoded the earlier mirror URL MUST migrate to the new path; the canonical-formats.mdx migration section documents the move. No transitional redirect is currently published (the earlier subdomain was never provisioned).
   *
   * For seller-bespoke formats (a publisher's `acme_homepage_takeover` that doesn't fit IAB conventions), each `v1_format_ref[].agent_url` is the seller's own agent_url and the id is seller-namespaced. These won't appear in `v1-canonical-mapping.json`'s registry; they're seller-asserted only.
   */
  v1_format_ref?: FormatReferenceStructuredObject[];
  format_schema?: PlatformExtensionReference;
} & (
    | ImageFormatDeclaration
    | HTML5FormatDeclaration
    | DisplayTagFormatDeclaration
    | ImageCarouselFormatDeclaration
    | HostedVideoFormatDeclaration
    | VASTVideoFormatDeclaration
    | HostedAudioFormatDeclaration
    | DAASTAudioFormatDeclaration
    | SponsoredPlacementFormatDeclaration
    | NativeInFeedFormatDeclaration
    | ResponsiveCreativeFormatDeclaration
    | AgentPlacementFormatDeclaration
    | CustomFormatDeclaration
  );

// core/real-estate-item.json
/**
 * A property listing within a real-estate-type catalog. Carries the address, pricing, and specification data that platforms use for real estate ads and dynamic remarketing. Maps to Google DynamicRealEstateAsset, Meta home listing catalogs, and similar formats.
 */
export interface RealEstateItem {
  /**
   * Unique identifier for this property listing.
   */
  listing_id: string;
  /**
   * Listing title (e.g., 'Spacious 3BR Apartment in Jordaan').
   */
  title: string;
  /**
   * Property address.
   */
  address: {
    /**
     * Street address.
     */
    street?: string;
    /**
     * City name.
     */
    city?: string;
    /**
     * State, province, or region.
     */
    region?: string;
    /**
     * Postal or ZIP code.
     */
    postal_code?: string;
    /**
     * ISO 3166-1 alpha-2 country code.
     * @pattern ^[A-Z]{2}$
     */
    country?: string;
  };
  price?: Price;
  /**
   * Type of property.
   */
  property_type?: 'house' | 'apartment' | 'condo' | 'townhouse' | 'land' | 'commercial';
  /**
   * Whether the property is for sale or rent.
   */
  listing_type?: 'for_sale' | 'for_rent';
  /**
   * Number of bedrooms.
   * @minimum 0
   */
  bedrooms?: number;
  /**
   * Number of bathrooms (e.g., 2.5 for two full and one half bath).
   * @minimum 0
   */
  bathrooms?: number;
  /**
   * Property size.
   */
  area?: {
    /**
     * Area value.
     * @minimum 0
     */
    value: number;
    /**
     * Area unit.
     */
    unit: 'sqft' | 'sqm';
  };
  /**
   * Property description.
   */
  description?: string;
  /**
   * Geographic coordinates of the property.
   */
  location?: {
    /**
     * Latitude in decimal degrees (WGS 84).
     * @minimum -90
     * @maximum 90
     */
    lat: number;
    /**
     * Longitude in decimal degrees (WGS 84).
     * @minimum -180
     * @maximum 180
     */
    lng: number;
  };
  /**
   * Primary property image URL.
   */
  image_url?: string;
  /**
   * Listing page URL.
   */
  url?: string;
  /**
   * Neighborhood or area name.
   */
  neighborhood?: string;
  /**
   * Year the property was built.
   */
  year_built?: number;
  /**
   * Tags for filtering (e.g., 'garden', 'parking', 'renovated', 'waterfront').
   */
  tags?: string[];
  /**
   * Typed creative asset pools for this property listing. Uses the same OfferingAssetGroup structure as offering-type catalogs. Standard group IDs: 'images_landscape' (exterior/interior hero), 'images_vertical' (9:16 for Stories), 'images_square' (1:1). Enables formats to declare typed image requirements that map unambiguously to the right asset regardless of platform.
   */
  assets?: OfferingAssetGroup[];
  ext?: ExtensionObject;
}

// core/requirements/asset-requirements.json
/**
 * Technical requirements for creative assets. The applicable schema is determined by the sibling asset_type field.
 */
export type AssetRequirements =
  | ImageAssetRequirements
  | VideoAssetRequirements
  | AudioAssetRequirements
  | TextAssetRequirements
  | MarkdownAssetRequirements
  | HTMLAssetRequirements
  | CSSAssetRequirements
  | JavaScriptAssetRequirements
  | VASTAssetRequirements
  | DAASTAssetRequirements
  | URLAssetRequirements
  | WebhookAssetRequirements;
/**
 * Requirements for image creative assets. These define the technical constraints for image files.
 */
export interface ImageAssetRequirements {
  /**
   * Minimum width. Interpretation depends on unit (default: pixels). For exact dimensions, set min_width = max_width.
   */
  min_width?: number;
  /**
   * Maximum width. Interpretation depends on unit (default: pixels). For exact dimensions, set min_width = max_width.
   */
  max_width?: number;
  /**
   * Minimum height. Interpretation depends on unit (default: pixels). For exact dimensions, set min_height = max_height.
   */
  min_height?: number;
  /**
   * Maximum height. Interpretation depends on unit (default: pixels). For exact dimensions, set min_height = max_height.
   */
  max_height?: number;
  unit?: DimensionUnit;
  /**
   * Required aspect ratio (e.g., '16:9', '1:1', '1.91:1')
   * @pattern ^\d+(\.\d+)?:\d+(\.\d+)?$
   */
  aspect_ratio?: string;
  /**
   * Accepted image file formats
   */
  formats?: ('jpg' | 'jpeg' | 'png' | 'gif' | 'webp' | 'svg' | 'avif' | 'tiff' | 'pdf' | 'eps')[];
  /**
   * Minimum resolution in dots per inch. Always in DPI regardless of the dimension unit. Standard print requires 300 DPI, newspaper 150 DPI.
   * @minimum 1
   */
  min_dpi?: number;
  /**
   * Required bleed area beyond the trim size. The submitted image must be larger than the declared dimensions: total width = trim width + left bleed + right bleed, total height = trim height + top bleed + bottom bleed. For uniform bleed: total = trim + (2 * uniform). Uses the same unit as the parent dimensions.
   */
  bleed?:
    | {
        /**
         * Same bleed on all four sides
         * @minimum 0
         */
        uniform: number;
      }
    | {
        /**
         * @minimum 0
         */
        top: number;
        /**
         * @minimum 0
         */
        right: number;
        /**
         * @minimum 0
         */
        bottom: number;
        /**
         * @minimum 0
         */
        left: number;
      };
  /**
   * Required color space. Print typically requires CMYK.
   */
  color_space?: 'rgb' | 'cmyk' | 'grayscale';
  /**
   * Maximum file size in kilobytes
   * @minimum 1
   */
  max_file_size_kb?: number;
  /**
   * Whether the image must support transparency (requires PNG, WebP, or GIF)
   */
  transparency_required?: boolean;
  /**
   * Whether animated images (GIF, animated WebP) are accepted
   */
  animation_allowed?: boolean;
  /**
   * Maximum animation duration in milliseconds (if animation_allowed is true)
   * @minimum 0
   */
  max_animation_duration_ms?: number;
  /**
   * Maximum weight in grams for the finished physical piece (print inserts, flyers). Affects postage calculations and production constraints. Only applicable to print channels.
   */
  max_weight_grams?: number;
}
/**
 * Requirements for video creative assets. These define the technical constraints for video files.
 */
export interface VideoAssetRequirements {
  /**
   * Minimum width in pixels
   * @minimum 1
   */
  min_width?: number;
  /**
   * Maximum width in pixels
   * @minimum 1
   */
  max_width?: number;
  /**
   * Minimum height in pixels
   * @minimum 1
   */
  min_height?: number;
  /**
   * Maximum height in pixels
   * @minimum 1
   */
  max_height?: number;
  /**
   * Required aspect ratio (e.g., '16:9', '9:16')
   * @pattern ^\d+:\d+$
   */
  aspect_ratio?: string;
  /**
   * Minimum duration in milliseconds
   * @minimum 1
   */
  min_duration_ms?: number;
  /**
   * Maximum duration in milliseconds
   * @minimum 1
   */
  max_duration_ms?: number;
  /**
   * Accepted video container formats
   */
  containers?: ('mp4' | 'webm' | 'mov' | 'avi' | 'mkv')[];
  /**
   * Accepted video codecs
   */
  codecs?: ('h264' | 'h265' | 'vp8' | 'vp9' | 'av1' | 'prores')[];
  /**
   * Maximum file size in kilobytes
   * @minimum 1
   */
  max_file_size_kb?: number;
  /**
   * Minimum video bitrate in kilobits per second
   * @minimum 1
   */
  min_bitrate_kbps?: number;
  /**
   * Maximum video bitrate in kilobits per second
   * @minimum 1
   */
  max_bitrate_kbps?: number;
  /**
   * Accepted frame rates in frames per second (e.g., [24, 30, 60])
   */
  frame_rates?: number[];
  /**
   * Whether the video must include an audio track
   */
  audio_required?: boolean;
  frame_rate_type?: FrameRateType;
  scan_type?: ScanType;
  gop_type?: GOPType;
  /**
   * Minimum keyframe interval in seconds
   * @minimum 0
   */
  min_gop_interval_seconds?: number;
  /**
   * Maximum keyframe interval in seconds. SSAI typically requires 1-2 second intervals.
   * @minimum 0
   */
  max_gop_interval_seconds?: number;
  moov_atom_position?: MoovAtomPosition;
  /**
   * Accepted audio codecs (e.g., ['aac', 'pcm', 'ac3'])
   */
  audio_codecs?: ('aac' | 'pcm' | 'ac3' | 'eac3' | 'mp3' | 'opus' | 'vorbis' | 'flac')[];
  /**
   * Accepted audio sample rates in Hz (e.g., [44100, 48000])
   */
  audio_sample_rates?: number[];
  /**
   * Accepted audio channel configurations
   */
  audio_channels?: AudioChannelLayout[];
  /**
   * Target integrated loudness in LUFS (e.g., -24 for broadcast, -16 for streaming)
   */
  loudness_lufs?: number;
  /**
   * Acceptable deviation from loudness_lufs target in dB (e.g., 2 means -22 to -26 LUFS for a -24 target)
   * @minimum 0
   */
  loudness_tolerance_db?: number;
  /**
   * Maximum true peak level in dBFS (e.g., -2 for broadcast)
   */
  true_peak_dbfs?: number;
}
/**
 * Requirements for audio creative assets.
 */
export interface AudioAssetRequirements {
  /**
   * Minimum duration in milliseconds
   * @minimum 1
   */
  min_duration_ms?: number;
  /**
   * Maximum duration in milliseconds
   * @minimum 1
   */
  max_duration_ms?: number;
  /**
   * Accepted audio file formats
   */
  formats?: ('mp3' | 'aac' | 'wav' | 'ogg' | 'flac')[];
  /**
   * Maximum file size in kilobytes
   * @minimum 1
   */
  max_file_size_kb?: number;
  /**
   * Accepted sample rates in Hz (e.g., [44100, 48000])
   */
  sample_rates?: number[];
  /**
   * Accepted audio channel configurations
   */
  channels?: ('mono' | 'stereo')[];
  /**
   * Minimum audio bitrate in kilobits per second
   * @minimum 1
   */
  min_bitrate_kbps?: number;
  /**
   * Maximum audio bitrate in kilobits per second
   * @minimum 1
   */
  max_bitrate_kbps?: number;
}
/**
 * Requirements for text creative assets such as headlines, body copy, and CTAs.
 */
export interface TextAssetRequirements {
  /**
   * Minimum character length
   * @minimum 0
   */
  min_length?: number;
  /**
   * Maximum character length
   * @minimum 1
   */
  max_length?: number;
  /**
   * Minimum number of lines
   * @minimum 1
   */
  min_lines?: number;
  /**
   * Maximum number of lines
   * @minimum 1
   */
  max_lines?: number;
  /**
   * Regex pattern defining allowed characters (e.g., '^[a-zA-Z0-9 .,!?-]+$')
   */
  character_pattern?: string;
  /**
   * List of prohibited words or phrases
   */
  prohibited_terms?: string[];
  /**
   * Closed set of permitted string values for this text slot. When present, a conformant implementation MUST reject any submitted content not in this list with `CREATIVE_VALUE_NOT_ALLOWED` (echoing the offending field path in `error.field` and the allowed list in `error.details.allowed_values`). Matching is case-sensitive; producers MUST supply exact casing. If the submitted value contains unresolved template tokens (e.g., {{product_name}}), validation against allowed_values MUST be deferred until interpolation is complete. All declared constraints (allowed_values, character_pattern, max_length, etc.) are conjunctive — submitted content must satisfy every applicable constraint simultaneously.
   */
  allowed_values?: string[];
}
/**
 * Requirements for markdown creative assets.
 */
export interface MarkdownAssetRequirements {
  /**
   * Maximum character length
   * @minimum 1
   */
  max_length?: number;
}
/**
 * Requirements for HTML creative assets. These define the execution environment constraints that the HTML must be compatible with.
 */
export interface HTMLAssetRequirements {
  /**
   * Maximum file size in kilobytes for the HTML asset
   * @minimum 1
   */
  max_file_size_kb?: number;
  /**
   * Sandbox environment the HTML must be compatible with. 'none' = direct DOM access, 'iframe' = standard iframe isolation, 'safeframe' = IAB SafeFrame container, 'fencedframe' = Privacy Sandbox fenced frame
   */
  sandbox?: 'none' | 'iframe' | 'safeframe' | 'fencedframe';
  /**
   * Whether the HTML creative can load external resources (scripts, images, fonts, etc.). When false, all resources must be inlined or bundled.
   */
  external_resources_allowed?: boolean;
  /**
   * List of domains the HTML creative may reference for external resources. Only applicable when external_resources_allowed is true.
   */
  allowed_external_domains?: string[];
}
/**
 * Requirements for CSS creative assets.
 */
export interface CSSAssetRequirements {
  /**
   * Maximum file size in kilobytes
   * @minimum 1
   */
  max_file_size_kb?: number;
}
/**
 * Requirements for JavaScript creative assets. These define the execution environment constraints that the JavaScript must be compatible with.
 */
export interface JavaScriptAssetRequirements {
  /**
   * Maximum file size in kilobytes for the JavaScript asset
   * @minimum 1
   */
  max_file_size_kb?: number;
  /**
   * Required JavaScript module format. 'script' = classic script, 'module' = ES modules, 'iife' = immediately invoked function expression
   */
  module_type?: 'script' | 'module' | 'iife';
  /**
   * Whether the JavaScript must use strict mode
   */
  strict_mode_required?: boolean;
  /**
   * Whether the JavaScript can load external resources dynamically
   */
  external_resources_allowed?: boolean;
  /**
   * List of domains the JavaScript may reference for external resources. Only applicable when external_resources_allowed is true.
   */
  allowed_external_domains?: string[];
}
/**
 * Requirements for VAST (Video Ad Serving Template) creative assets.
 */
export interface VASTAssetRequirements {
  /**
   * Required VAST version
   */
  vast_version?: '2.0' | '3.0' | '4.0' | '4.1' | '4.2';
}
/**
 * Requirements for DAAST (Digital Audio Ad Serving Template) creative assets.
 */
export interface DAASTAssetRequirements {
  /**
   * Required DAAST version. DAAST 1.0 is the current IAB standard.
   */
  daast_version?: '1.0';
}
/**
 * Requirements for URL assets such as click-through URLs, tracking pixels, and landing pages.
 */
export interface URLAssetRequirements {
  /**
   * Purpose this URL slot serves in the format — distinct from `url_type` on the manifest-side asset (which declares the receiver's invocation mechanism). A slot can be `click_tracker` (purpose) and accept a `tracker_pixel` (mechanism) URL, or `clickthrough` (purpose) and accept a `clickthrough` (mechanism) URL. Complements `asset_role` (human-readable label) by providing a machine-readable enum and serves as the receiver's fallback signal when a manifest URL asset omits `url_type`.
   */
  role?:
    | 'clickthrough'
    | 'landing_page'
    | 'impression_tracker'
    | 'click_tracker'
    | 'viewability_tracker'
    | 'third_party_tracker';
  /**
   * Allowed URL protocols. HTTPS is recommended for all ad URLs.
   */
  protocols?: ('https' | 'http')[];
  /**
   * List of allowed domains for the URL
   */
  allowed_domains?: string[];
  /**
   * Maximum URL length in characters
   * @minimum 1
   */
  max_length?: number;
  /**
   * Whether the URL supports macro substitution (e.g., ${CACHEBUSTER})
   */
  macro_support?: boolean;
}
/**
 * Requirements for webhook creative assets.
 */
export interface WebhookAssetRequirements {
  /**
   * Allowed HTTP methods
   */
  methods?: ('GET' | 'POST')[];
}


// core/requirements/catalog-field-binding.json
/**
 * Maps a format template slot to a catalog item field or typed asset pool. The 'kind' field identifies the binding variant. All bindings are optional — agents can still infer mappings without them.
 */
export type CatalogFieldBinding =
  | ScalarBinding
  | AssetPoolBinding
  | {
      kind: 'catalog_group';
      /**
       * The asset_group_id of a repeatable_group in the format's assets array.
       */
      format_group_id: string;
      /**
       * Each repetition of the format's repeatable_group maps to one item from the catalog.
       */
      catalog_item: true;
      /**
       * Scalar and asset pool bindings that apply within each repetition of the group. Nested catalog_group bindings are not permitted.
       */
      per_item_bindings?: (ScalarBinding | AssetPoolBinding)[];
      ext?: ExtensionObject;
    };

/**
 * Maps an individual format asset to a catalog item field via dot-notation path.
 */
export interface ScalarBinding {
  kind: 'scalar';
  /**
   * The asset_id from the format's assets array. Identifies which individual template slot this binding applies to.
   */
  asset_id: string;
  /**
   * Dot-notation path to the field on the catalog item (e.g., 'name', 'price.amount', 'location.city').
   */
  catalog_field: string;
  ext?: ExtensionObject;
}
/**
 * Maps an individual format asset to a typed asset pool on the catalog item (e.g., images_landscape, images_vertical, logo). The format slot receives the first item in the pool.
 */
export interface AssetPoolBinding {
  kind: 'asset_pool';
  /**
   * The asset_id from the format's assets array. Identifies which individual template slot this binding applies to.
   */
  asset_id: string;
  /**
   * The asset_group_id on the catalog item's assets array to pull from (e.g., 'images_landscape', 'images_vertical', 'logo').
   */
  asset_group_id: string;
  ext?: ExtensionObject;
}


// core/requirements/catalog-requirements.json
/**
 * Format-level declaration of what catalog feeds a creative needs. Formats that render product listings, store locators, or promotional content declare which catalog types must be synced and what fields each catalog must provide. Buyers use this to ensure the right catalogs are synced before submitting creatives.
 */
export interface CatalogRequirements {
  catalog_type: CatalogType;
  /**
   * Whether this catalog type must be present. When true, creatives using this format must reference a synced catalog of this type.
   */
  required?: boolean;
  /**
   * Minimum number of items the catalog must contain for this format to render properly (e.g., a carousel might require at least 3 products)
   * @minimum 1
   */
  min_items?: number;
  /**
   * Maximum number of items the format can render. Items beyond this limit are ignored. Useful for fixed-slot layouts (e.g., a 3-product card) or feed-size constraints.
   * @minimum 1
   */
  max_items?: number;
  /**
   * Fields that must be present and non-empty on every item in the catalog. Field names are catalog-type-specific (e.g., 'title', 'price', 'image_url' for product catalogs; 'store_id', 'quantity' for inventory feeds).
   */
  required_fields?: string[];
  /**
   * Accepted feed formats for this catalog type. When specified, the synced catalog must use one of these formats. When omitted, any format is accepted.
   */
  feed_formats?: FeedFormat[];
  /**
   * Per-item creative asset requirements. Declares what asset groups (headlines, images, videos) each catalog item must provide in its assets array, along with count bounds and per-asset technical constraints. Applicable to 'offering' and all vertical catalog types (hotel, flight, job, etc.) whose items carry typed assets.
   */
  offering_asset_constraints?: OfferingAssetConstraint[];
  /**
   * Explicit mappings from format template slots to catalog item fields or typed asset pools. Optional — creative agents can infer mappings without them, but bindings make the relationship self-describing and enable validation. Covers scalar fields (asset_id → catalog_field), asset pools (asset_id → asset_group_id on the catalog item), and repeatable groups that iterate over catalog items.
   */
  field_bindings?: CatalogFieldBinding[];
}
/**
 * Declares per-group creative requirements that each offering must satisfy. Allows formats to specify what asset groups (headlines, images, videos) offerings must provide, along with count and per-asset technical constraints.
 */
export interface OfferingAssetConstraint {
  /**
   * The asset group this constraint applies to. Values are format-defined vocabulary — each format chooses its own group IDs (e.g., 'headlines', 'images', 'videos'). Buyers discover them via list_creative_formats.
   */
  asset_group_id: string;
  asset_type: AssetContentType;
  /**
   * Whether this asset group must be present in each offering. Defaults to true.
   */
  required?: boolean;
  /**
   * Minimum number of items required in this group.
   * @minimum 1
   */
  min_count?: number;
  /**
   * Maximum number of items allowed in this group.
   * @minimum 1
   */
  max_count?: number;
  asset_requirements?: AssetRequirements;
  ext?: ExtensionObject;
}

// core/response.json
/**
 * Protocol-level response wrapper (MCP/A2A) - contains AdCP task data plus protocol fields
 */
export interface ProtocolResponse {
  /**
   * Human-readable summary
   */
  message: string;
  /**
   * Session continuity identifier
   */
  context_id?: string;
  /**
   * AdCP task-specific response data (see individual task response schemas)
   */
  data?: unknown;
}


// core/seller-agent-ref.json
/**
 * Structured reference to a seller agent. The canonical identifier is the agent's URL as declared in the property publisher's adagents.json `authorized_agents[].url`. The optional `id` slot is reserved for a future registry-assigned stable identifier; it is not used today. This shape mirrors `format-id` and `ProviderEntry` — URL-first, with an ID slot for forward compatibility.
 */
export interface SellerAgentReference {
  /**
   * The seller agent's API endpoint URL as declared in the property publisher's adagents.json `authorized_agents[].url`. MUST use the `https://` scheme. Receivers compare this URL against the `authorized_agents` list using the AdCP URL canonicalization rules — not byte-equality — and reject mismatches with `seller_not_authorized`. See docs/reference/url-canonicalization.
   */
  agent_url: string;
  /**
   * Reserved for a future registry-assigned stable seller identifier. Not used today — senders MUST NOT populate this field until a registry is defined. When a future release populates both `agent_url` and `id`, `agent_url` remains authoritative and `id` is advisory.
   * @minLength 1
   * @pattern ^[a-zA-Z0-9_-]+$
   */
  id?: string;
}


// core/signal-definition.json
/**
 * Personal data categories that may be restricted from use in audience targeting. Combines GDPR Article 9 special categories with US civil-rights protected classes (FHA familial_status, ADEA age). Used in two places: (1) on campaign plans via restricted_attributes to declare which categories are prohibited, and (2) on signal-definition.json via restricted_attributes to declare which categories a signal touches. Governance agents match plan restrictions against signal declarations for structural validation.
 */
export type RestrictedAttribute =
  | 'racial_ethnic_origin'
  | 'political_opinions'
  | 'religious_beliefs'
  | 'trade_union_membership'
  | 'health_data'
  | 'sex_life_sexual_orientation'
  | 'genetic_data'
  | 'biometric_data'
  | 'age'
  | 'familial_status';

/**
 * Definition of a signal in a published adagents.json signal catalog. The catalog's publishing domain supplies the namespace, so this definition carries a local id rather than a signal_ref. Media-buy products reference this definition with signal_ref scope 'data_provider', data_provider_domain set to the catalog domain, and signal_id set to this id.
 */
export interface SignalDefinition {
  /**
   * Signal identifier within this published signal catalog
   * @pattern ^[a-zA-Z0-9_-]+$
   */
  id: string;
  /**
   * Human-readable signal name
   * @minLength 1
   * @maxLength 255
   */
  name: string;
  /**
   * Detailed description of what this signal represents and how it's derived
   * @maxLength 2000
   */
  description?: string;
  value_type: SignalValueType;
  /**
   * Tags for grouping and filtering signals within the catalog
   */
  tags?: string[];
  /**
   * For categorical signals, the valid values users can be assigned
   */
  allowed_values?: string[];
  /**
   * Restricted attribute categories this signal touches. Data providers SHOULD declare these so governance agents can structurally match signals against a plan's restricted_attributes without relying on semantic inference from the signal name or description.
   */
  restricted_attributes?: RestrictedAttribute[];
  /**
   * Policy categories this signal is sensitive for (e.g., a children's interest signal declares ['children_directed']). Governance agents match these against a plan's policy_categories to flag sensitive data usage.
   */
  policy_categories?: string[];
  /**
   * For numeric signals, the valid value range
   */
  range?: {
    /**
     * Minimum value
     */
    min: number;
    /**
     * Maximum value
     */
    max: number;
    /**
     * Unit of measurement (e.g., 'score', 'dollars', 'years')
     */
    unit?: string;
  };
}


// core/signal-pricing-option.json
/**
 * Deprecated — use vendor-pricing-option.json for new implementations. This alias is retained for backward compatibility.
 */
export type SignalPricingOption = {
  /**
   * Opaque identifier for this pricing option, unique within the vendor agent. Pass this in report_usage to identify which pricing option was applied.
   */
  pricing_option_id: string;
} & VendorPricing;

// core/store-item.json
/**
 * A physical store or location within a store-type catalog. Carries the location data, catchment areas, and metadata that platforms use for proximity targeting, store locator creatives, and inventory-aware ad serving.
 */
export interface StoreItem {
  /**
   * Unique identifier for this store. Used to reference specific stores in targeting, inventory feeds, and creative templates.
   */
  store_id: string;
  /**
   * Human-readable store name (e.g., 'Amsterdam Flagship', 'Brooklyn Heights').
   */
  name: string;
  /**
   * Geographic coordinates of the store.
   */
  location: {
    /**
     * Latitude in decimal degrees (WGS 84).
     * @minimum -90
     * @maximum 90
     */
    lat: number;
    /**
     * Longitude in decimal degrees (WGS 84).
     * @minimum -180
     * @maximum 180
     */
    lng: number;
  };
  /**
   * Structured address for display and geocoding fallback.
   */
  address?: {
    /**
     * Street address (e.g., '123 Main St').
     */
    street?: string;
    /**
     * City name.
     */
    city?: string;
    /**
     * State, province, or region. ISO 3166-2 subdivision code preferred (e.g., 'NL-NH', 'US-CA').
     */
    region?: string;
    /**
     * Postal or ZIP code.
     */
    postal_code?: string;
    /**
     * ISO 3166-1 alpha-2 country code.
     * @pattern ^[A-Z]{2}$
     */
    country?: string;
  };
  /**
   * Catchment areas for this store. Each defines a reachable area using travel time (isochrone), simple radius, or pre-computed GeoJSON. Multiple catchments allow different modes — e.g., 15-minute drive AND 10-minute walk.
   */
  catchments?: Catchment[];
  /**
   * Store phone number in E.164 format (e.g., '+31201234567').
   */
  phone?: string;
  /**
   * Store-specific page URL (e.g., store locator detail page).
   */
  url?: string;
  /**
   * Operating hours. Keys are ISO day names (monday–sunday), values are time ranges.
   */
  hours?: {
    /**
     * Time range in HH:MM-HH:MM format (e.g., '09:00-21:00'). Use 'closed' for days the store is not open.
     */
    [k: string]: string | undefined;
  };
  /**
   * Tags for filtering stores in targeting and creative selection (e.g., 'flagship', 'pickup', 'pharmacy').
   */
  tags?: string[];
  ext?: ExtensionObject;
}

// core/truncation-sentinel.json
/**
 * Universal AdCP sentinel value that replaces a field's content when the seller has truncated it due to a size cap. Used wherever an AdCP field may carry large user-supplied content (e.g., webhook request/response payloads under a future `include_webhook_payloads` extension, large structured-event blobs, captured response bodies) and the seller has elected to surface a bounded preview instead of the full value. The leading-underscore key `_truncation` is a deliberate control marker — its presence on an object is the discriminator that distinguishes a truncation sentinel from the natural value the field would otherwise carry. Schemas that may carry truncated content reference this shape via `oneOf` against the natural value type — e.g., `{ "oneOf": [ { "$ref": "#/definitions/NaturalValue" }, { "$ref": "/schemas/core/truncation-sentinel.json" } ] }`. Receivers detect a sentinel by testing `'_truncation' in value`. See snapshot-and-log.mdx § Webhook activity log pattern for the cross-resource context this sentinel was introduced under.
 */
export interface TruncationSentinel {
  /**
   * Truncation envelope. The leading underscore is a deliberate signal that this property is a control marker and not a payload field — the natural value being surfaced will not have a `_truncation` key. `additionalProperties: true` so future revisions of this contract can add classification fields without a forward-compat break.
   */
  _truncation: {
    /**
     * Size of the untruncated original content in bytes, measured before any encoding overhead. Lets the receiver decide whether to fetch the full value via a payload-bearing surface (when one exists) or proceed with the preview.
     * @minimum 0
     */
    original_size_bytes: number;
    /**
     * Optional bounded human-readable excerpt of the original content. Sellers SHOULD keep previews under 8 KiB and SHOULD truncate on a UTF-8 codepoint boundary. Absent when the seller cannot safely surface even a preview (e.g., the original content is binary and not text-decodable, or seller policy forbids any payload surfacing). Receivers MUST NOT parse `preview` as a complete representation of the original value.
     */
    preview?: string;
    /**
     * Hint for how to render `preview`. Common values: `text` (plain UTF-8), `json` (JSON fragment), `base64` (base64-encoded binary), `xml`, `html`. The list is open — adopters MAY use other MIME-derived shorthands. Receivers SHOULD treat unknown values as `text` and SHOULD NOT reject the sentinel when the value is unfamiliar.
     */
    preview_format?: string;
  };
}


// core/vehicle-item.json
/**
 * A vehicle listing within a vehicle-type catalog. Carries the make/model, pricing, and specification data that platforms use for automotive inventory ads. Maps to Meta Automotive Inventory Ads, Microsoft Auto Inventory feeds, Google vehicle ads, and similar formats.
 */
export interface VehicleItem {
  /**
   * Unique identifier for this vehicle listing.
   */
  vehicle_id: string;
  /**
   * Listing title (e.g., '2024 Honda Civic EX Sedan').
   */
  title: string;
  /**
   * Vehicle manufacturer (e.g., 'Honda', 'Ford', 'BMW').
   */
  make: string;
  /**
   * Vehicle model (e.g., 'Civic', 'F-150', 'X5').
   */
  model: string;
  /**
   * Model year.
   * @minimum 1900
   */
  year: number;
  price?: Price;
  /**
   * Vehicle condition.
   */
  condition?: 'new' | 'used' | 'certified_pre_owned';
  /**
   * Vehicle Identification Number (17-character VIN).
   */
  vin?: string;
  /**
   * Trim level (e.g., 'EX', 'Limited', 'Sport').
   */
  trim?: string;
  /**
   * Odometer reading.
   */
  mileage?: {
    /**
     * Mileage value.
     * @minimum 0
     */
    value: number;
    /**
     * Distance unit.
     */
    unit: 'km' | 'mi';
  };
  /**
   * Vehicle body style.
   */
  body_style?: 'sedan' | 'suv' | 'truck' | 'coupe' | 'convertible' | 'wagon' | 'van' | 'hatchback';
  /**
   * Transmission type.
   */
  transmission?: 'automatic' | 'manual' | 'cvt';
  /**
   * Fuel or powertrain type.
   */
  fuel_type?: 'gasoline' | 'diesel' | 'electric' | 'hybrid' | 'plug_in_hybrid';
  /**
   * Exterior color.
   */
  exterior_color?: string;
  /**
   * Interior color.
   */
  interior_color?: string;
  /**
   * Dealer or vehicle location.
   */
  location?: {
    /**
     * Latitude in decimal degrees (WGS 84).
     * @minimum -90
     * @maximum 90
     */
    lat: number;
    /**
     * Longitude in decimal degrees (WGS 84).
     * @minimum -180
     * @maximum 180
     */
    lng: number;
  };
  /**
   * Primary vehicle image URL.
   */
  image_url?: string;
  /**
   * Vehicle listing page URL.
   */
  url?: string;
  /**
   * Tags for filtering (e.g., 'low-mileage', 'one-owner', 'dealer-certified').
   */
  tags?: string[];
  /**
   * Typed creative asset pools for this vehicle. Uses the same OfferingAssetGroup structure as offering-type catalogs. Standard group IDs: 'images_landscape' (exterior hero), 'images_vertical' (9:16 for Stories), 'images_square' (1:1). Enables formats to declare typed image requirements that map unambiguously to the right asset regardless of platform.
   */
  assets?: OfferingAssetGroup[];
  ext?: ExtensionObject;
}

// core/webhook-challenge-response.json
/**
 * Response body a receiver returns to prove control of an account-level notification_configs[] URL. The receiver must echo the challenge value from webhook-challenge.json in exactly one of `challenge` or `token`.
 */
export interface WebhookChallengeResponse {
  /**
   * Echo of the challenge value supplied by the seller.
   * @minLength 32
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{32,255}$
   */
  challenge?: string;
  /**
   * Backward-compatible alias for `challenge`. Receivers SHOULD prefer `challenge`; sellers MUST accept either field.
   * @minLength 32
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{32,255}$
   */
  token?: string;
}


// core/webhook-challenge.json
/**
 * Proof-of-control challenge payload sent by a seller to an account-level notification_configs[] URL before activating a new or changed active subscriber. The seller sends this payload as an HTTPS POST after URL normalization and SSRF validation, and before treating the subscriber as active. The challenge POST itself MUST be signed with the seller's RFC 9421 webhook-signing key even when the candidate config selects legacy delivery auth; `delivery_auth` describes the future webhook delivery mode, not the challenge's own signing mode.
 */
export interface WebhookChallenge {
  /**
   * Discriminator for endpoint proof-of-control challenges.
   */
  type: 'webhook.challenge';
  /**
   * Opaque, cryptographically random value that the receiver must echo in the response body. Recommended encoding: base64url without padding.
   * @minLength 32
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{32,255}$
   */
  challenge: string;
  /**
   * Seller account identifier for the account whose notification_configs[] entry is being challenged.
   */
  account_id: string;
  /**
   * Buyer-supplied subscriber identifier from the notification_configs[] entry being challenged.
   * @minLength 1
   * @maxLength 64
   * @pattern ^[A-Za-z0-9_.:-]{1,64}$
   */
  subscriber_id: string;
  /**
   * Exact seller agent URL whose RFC 9421 webhook-signing key signs this challenge and that will send subsequent webhooks.
   */
  seller_agent_url: string;
  /**
   * Authentication/signing mode the seller will use for subsequent webhooks delivered to this notification config.
   */
  delivery_auth: {
    /**
     * Future webhook delivery authentication mode. `rfc9421` is used when notification_configs[].authentication is absent; Bearer and HMAC-SHA256 are the deprecated legacy modes selected by notification_configs[].authentication.
     */
    mode: 'rfc9421' | 'Bearer' | 'HMAC-SHA256';
    /**
     * SHA-256 hex fingerprint of the exact legacy credential string supplied in notification_configs[].authentication.credentials. Required when mode is Bearer or HMAC-SHA256; absent for rfc9421.
     * @pattern ^[a-f0-9]{64}$
     */
    credential_fingerprint?: string;
  };
  /**
   * Normalized notification types requested by the subscriber at the time of the challenge. Part of the endpoint proof scope; changing event_types[] requires a fresh challenge before the new set can become active.
   */
  event_types: NotificationType[];
}


// core/wholesale-feed-event.json
/**
 * A single change event emitted by an AdCP agent's wholesale product feed or wholesale signals feed and delivered inside wholesale-feed-webhook payloads. Events are denormalized — the payload carries the post-change state of a buyable product or signal so consumers can update local state without a follow-up get_products / get_signals call. This is distinct from buyer-provided feeds managed by sync_catalogs. The discriminator is `event_type`; each branch defines the payload shape. See specs/wholesale-feed-webhooks.md for webhook delivery and reconciliation semantics.
 */
export type WholesaleFeedEvent = {
  /**
   * Stable logical event identifier for this wholesale feed change. MUST equal the enclosing webhook `notification_id`. UUID v7 is RECOMMENDED so receivers can detect obvious out-of-order delivery, but there is no durable cursor or event-polling API; missed or distrusted pushes are repaired through get_products / get_signals.
   * @format uuid
   */
  event_id: string;
  /**
   * Discriminator. Determines the shape of `payload`.
   */
  event_type:
    | 'product.created'
    | 'product.updated'
    | 'product.priced'
    | 'product.removed'
    | 'signal.created'
    | 'signal.updated'
    | 'signal.priced'
    | 'signal.removed'
    | 'wholesale_feed.bulk_change';
  /**
   * Entity class. 'product' for product.* events, 'signal' for signal.* events, 'feed' for wholesale_feed.bulk_change.
   */
  entity_type: 'product' | 'signal' | 'feed';
  /**
   * Entity identifier. For product.* events, the product_id. For signal.* events, the signal_agent_segment_id. For wholesale_feed.bulk_change, an agent-defined operation id.
   */
  entity_id: string;
  /**
   * ISO 8601 timestamp when the agent emitted the event. Advisory — consumers MUST order by event_id (UUID v7), not by created_at, to avoid clock-skew artifacts.
   * @format date-time
   */
  created_at: string;
  /**
   * Event-type-specific payload. Shape is determined by event_type per the oneOf below.
   */
  payload: {};
} & (
  | {
      event_type: 'product.created';
      entity_type?: 'product';
      payload?: {
        product_id: string;
        product: Product;
        applies_to: CacheLayerScope;
      };
    }
  | {
      event_type: 'product.updated';
      entity_type?: 'product';
      payload?: {
        product_id: string;
        product: Product;
        /**
         * Advisory list of changed top-level field names (e.g., ['format_ids', 'performance_standards']). Consumers MAY use for fine-grained re-render, but the product object is the source of truth for this webhook payload.
         */
        changed_fields?: string[];
        applies_to: CacheLayerScope;
      };
    }
  | {
      event_type: 'product.priced';
      entity_type?: 'product';
      payload?: {
        product_id: string;
        /**
         * Full post-change pricing_options array. NOT a delta — consumers replace the prior options with this list.
         */
        pricing_options: PricingOption[];
        /**
         * Optional. Lets consumers detect which pricing_option_ids were retired.
         */
        previous_pricing_option_ids?: string[];
        /**
         * When the price change takes effect. A value in the future is a pre-announcement: consumers MAY warm caches but MUST NOT bind decisions until the effective time has passed. See specs/wholesale-feed-webhooks.md §`effective_at` and pre-announce.
         * @format date-time
         */
        effective_at?: string;
        /**
         * Optional. When this event retracts a prior pre-announced *.priced (per the §`effective_at` and pre-announce rules), set this to the event_id of the announcement being retracted. Lets consumers detect retraction deterministically by event_id lookup rather than maintaining per-entity 'latest-event' state. When present, the retraction MUST carry effective_at <= the retracted event's effective_at.
         * @format uuid
         */
        retracts_event_id?: string;
        applies_to: CacheLayerScope;
      };
    }
  | {
      event_type: 'product.removed';
      entity_type?: 'product';
      payload?: {
        product_id: string;
        removal_reason?: RemovalReason;
        applies_to: CacheLayerScope;
      };
    }
  | {
      event_type: 'signal.created';
      entity_type?: 'signal';
      payload?: {
        signal_agent_segment_id: string;
        signal_ref?: SignalRef;
        applies_to: CacheLayerScope;
        signal: WholesaleSignalObject;
      };
    }
  | {
      event_type: 'signal.updated';
      entity_type?: 'signal';
      payload?: {
        signal_agent_segment_id: string;
        signal_ref?: SignalRef;
        /**
         * Advisory list of changed top-level field names. Consumers MAY use for fine-grained re-render, but the signal object is the source of truth for this webhook payload.
         */
        changed_fields?: string[];
        applies_to: CacheLayerScope;
        signal: WholesaleSignalObject;
      };
    }
  | {
      event_type: 'signal.priced';
      entity_type?: 'signal';
      payload?: {
        signal_agent_segment_id: string;
        signal_ref?: SignalRef;
        /**
         * Full post-change pricing_options array. NOT a delta.
         */
        pricing_options: VendorPricingOption[];
        previous_pricing_option_ids?: string[];
        /**
         * When the price change takes effect. A value in the future is a pre-announcement: consumers MAY warm caches but MUST NOT bind decisions until the effective time has passed. See specs/wholesale-feed-webhooks.md §`effective_at` and pre-announce.
         * @format date-time
         */
        effective_at?: string;
        /**
         * Optional. When this event retracts a prior pre-announced *.priced, set this to the event_id of the announcement being retracted. See product.priced for the full retraction contract.
         * @format uuid
         */
        retracts_event_id?: string;
        applies_to: CacheLayerScope;
      };
    }
  | {
      event_type: 'signal.removed';
      entity_type?: 'signal';
      payload?: {
        signal_agent_segment_id: string;
        signal_ref?: SignalRef;
        removal_reason?: RemovalReason;
        applies_to: CacheLayerScope;
      };
    }
  | {
      event_type: 'wholesale_feed.bulk_change';
      entity_type?: 'feed';
      payload?: {
        /**
         * Human-readable description of the bulk operation (e.g., 'Q3 2026 rate card refresh').
         */
        summary: string;
        /**
         * Approximate count of affected entities.
         * @minimum 1
         */
        affected_count: number;
        /**
         * Advisory recommendation. Consumers SHOULD repair by re-reading the affected feed named by affected_entity_type; the recommendation is not a synchronized trigger. Modeled as a single-value enum (not a boolean) so future minor versions can extend the recommendation vocabulary without a breaking shape change. Consumers MUST be prepared to ignore unknown recommendation values.
         */
        recommendation?: 'wholesale_resync';
        applies_to: CacheLayerScope;
        /**
         * Which wholesale feed this bulk operation touched. A bulk operation that changes both products and signals MUST emit one webhook per feed so each envelope carries the correct post-change wholesale_feed_version.
         */
        affected_entity_type: 'product' | 'signal';
      };
    }
);
/**
 * REQUIRED. Sellers MUST declare the cache layer explicitly on every *.created event. When introducing an entity that exists only in an account overlay (e.g., a custom product for a single account), the seller MUST emit { scope: 'account', account_ids: [...] } to prevent the entity from leaking into every consumer's public-layer cache. For public-layer additions, declare { scope: 'public' } explicitly rather than relying on a default — schema-required declaration prevents the quiet-failure path where a forgotten applies_to leaks an account-only entity to all consumers.
 */
export type CacheLayerScope =
  | {
      scope: 'public';
    }
  | {
      scope: 'account';
      /**
       * Optional. When present, names the accounts whose overlays are affected. When omitted, subscribers infer that their own principal's overlay is affected (they received the event because the per-subscriber scope filter routed it to them).
       */
      account_ids?: string[];
    };
/**
 * Why the entity was removed. 'withdrawn': seller-initiated, no resubmit path. 'cancellation': resource cancelled, may return. 'expired': time-bounded availability ended (flight ended, seasonal product retired). 'depublication': underlying property depublished (see publisher.adagents_changed in the registry feed). 'policy_takedown': governance-driven removal (AdCP governance agent OR external regulator/legal takedown). In-flight buys honor existing cancellation policy regardless of reason; storefront UX differs.
 */
export type RemovalReason = 'withdrawn' | 'cancellation' | 'expired' | 'depublication' | 'policy_takedown';
/**
 * Full post-change signal object.
 */
export interface WholesaleSignalObject {
  signal_ref?: SignalRef;
  signal_id?: SignalID;
  /**
   * Human-readable signal name
   * @minLength 1
   */
  name: string;
  /**
   * Detailed signal description
   * @minLength 1
   */
  description: string;
  /**
   * Optional link to published methodology, media-kit, or data documentation. For data_provider and signal_source refs, this SHOULD match or supplement the referenced definition.
   */
  methodology_url?: string;
  /**
   * When this listing record was last updated. This indicates freshness of the listing record, not an attestation that the underlying data or model was refreshed at that time.
   */
  last_updated?: string;
  value_type?: SignalValueType;
  categories?: string[];
  range?: {
    min: number;
    max: number;
  };
  /**
   * Opaque activation handle returned by the signals agent.
   * @minLength 1
   */
  signal_agent_segment_id: string;
  signal_type: SignalCatalogType;
  /**
   * @minLength 1
   */
  data_provider?: string;
  /**
   * @minimum 0
   * @maximum 100
   */
  coverage_percentage: number;
  deployments: Deployment[];
  pricing_options?: VendorPricingOption[];
}

// core/wholesale-feed-webhook.json
/**
 * Account-level webhook payload fired when a seller's wholesale product feed or wholesale signals feed changes. Registered through sync_accounts.accounts[].notification_configs[] using product.* / signal.* / wholesale_feed.bulk_change event_types. The payload carries the actual change event so receivers can update a local mirror without immediately re-reading the full feed. get_products / get_signals with if_wholesale_feed_version remain the repair and reconciliation path after missed, stale, or distrusted pushes. Capability consistency: product.* webhooks require wholesale get_products support; signal.* webhooks require wholesale get_signals support; wholesale_feed.bulk_change must name only a feed family backed by a declared wholesale repair path.
 */
export type WholesaleFeedWebhook = {
  [k: string]: unknown | undefined;
} & {
  /**
   * Sender-generated key stable across retries of the same webhook fire. Receivers MUST dedupe by this key, scoped to the authenticated sender identity.
   * @minLength 16
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{16,255}$
   */
  idempotency_key: string;
  /**
   * Stable identifier for this logical wholesale feed event. MUST equal event.event_id. Re-emissions of the same logical event reuse this value under a new idempotency_key.
   * @format uuid
   */
  notification_id: string;
  /**
   * Wholesale feed notification type discriminator. MUST match event.event_type.
   */
  notification_type:
    | 'product.created'
    | 'product.updated'
    | 'product.priced'
    | 'product.removed'
    | 'signal.created'
    | 'signal.updated'
    | 'signal.priced'
    | 'signal.removed'
    | 'wholesale_feed.bulk_change';
  /**
   * ISO 8601 timestamp when the seller initiated this webhook fire. Distinct from event.created_at, which is when the seller observed or recorded the feed change.
   * @format date-time
   */
  fired_at: string;
  /**
   * Identifies which notification_configs[] entry is receiving this fire. Echoed from the registered subscriber_id.
   * @minLength 1
   * @maxLength 64
   * @pattern ^[A-Za-z0-9_.:-]{1,64}$
   */
  subscriber_id: string;
  /**
   * Seller account identifier for the account scope that registered this webhook through sync_accounts.accounts[].notification_configs[]. Required because wholesale feed webhooks are account-anchored notifications.
   */
  account_id: string;
  /**
   * Opaque version token for the affected wholesale feed after this change. Receivers store it with their mirror and can pass it to get_products / get_signals as if_wholesale_feed_version to verify whether their local state is current.
   */
  wholesale_feed_version: string;
  /**
   * Opaque version token for the affected wholesale feed before this change, when the seller can cheaply provide it. Receivers MAY use this to detect obvious gaps, but MUST NOT require it.
   */
  previous_wholesale_feed_version?: string;
  /**
   * Cache layer affected by this change. MUST equal event.payload.applies_to.scope. Mirrors the cache_scope returned by get_products / get_signals for the affected wholesale feed.
   */
  cache_scope: 'public' | 'account';
  event: WholesaleFeedEvent;
  ext?: ExtensionObject;
};

// core/x-entity-types.json
/**
 * Registry of valid `x-entity` annotation values. Each value tags a schema field whose contents carry identity of the named entity type. The context-entity lint reads this registry to reject unknown `x-entity` values and to catch mismatches between storyboard capture and consume sites. See docs/contributing/x-entity-annotation.md for authoring guidance. To add a value, PR this file and extend the authoring doc.
 */
export type XEntityTypes =
  | 'advertiser_brand'
  | 'rights_holder_brand'
  | 'rights_grant'
  | 'account'
  | 'operator'
  | 'media_buy'
  | 'package'
  | 'product'
  | 'product_pricing_option'
  | 'vendor_pricing_option'
  | 'creative'
  | 'creative_format'
  | 'audience'
  | 'signal'
  | 'signal_activation_id'
  | 'event_source'
  | 'impairment'
  | 'collection_list'
  | 'property_list'
  | 'catalog'
  | 'property'
  | 'media_plan'
  | 'governance_plan'
  | 'governance_registry_policy'
