// creative/creative-purged-webhook.json
/**
 * Account-level push notification fired when a creative is destroyed from the seller's library — retention sweep, takedown enforcement, legal erasure. Fires per registered subscriber against each `notification_configs[]` entry whose `event_types` includes `creative.purged`. Distinct from `creative.status_changed` because purge is destruction, not a status transition — the creative is gone; status no longer applies. Soft purges retain a tombstone on `list_creatives` (with `include_purged: true`) for the seller's webhook retention window; hard purges do not — this webhook is the buyer's only signal. Sellers MUST NOT coalesce `creative.purged` fires (default no-coalescence window).
 */
export interface CreativePurgedWebhook {
  /**
   * Sender-generated key stable across retries of the same fire.
   * @minLength 16
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{16,255}$
   */
  idempotency_key: string;
  /**
   * Stable identifier for this purge event. Receivers correlate fires by this id; a single creative can only be purged once, so a new id implies a different creative or (rare) a re-emission of the same purge after retention-driven snapshot loss.
   * @minLength 1
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{1,255}$
   */
  notification_id: string;
  /**
   * Fixed notification type discriminator.
   */
  notification_type: 'creative.purged';
  /**
   * ISO 8601 timestamp when the seller initiated this fire. Sellers MUST fire `creative.purged` immediately after purge — coalescence is not permitted on this notification type.
   * @format date-time
   */
  fired_at: string;
  /**
   * Identifies which `notification_configs[]` entry on the recipient account is receiving this fire.
   * @minLength 1
   * @maxLength 64
   * @pattern ^[A-Za-z0-9_.:-]{1,64}$
   */
  subscriber_id: string;
  /**
   * Seller's identifier for the account that owned the purged creative.
   */
  account_id: string;
  /**
   * Seller's identifier for the purged creative. After a `soft` purge this id resolves on `list_creatives` (with `include_purged: true`) for the seller's tombstone retention window; after a `hard` purge no record remains.
   */
  creative_id: string;
  /**
   * `soft` — tombstone retained on `list_creatives` (with `include_purged: true`) for the seller's retention window (default 30 days, MUST match the `webhook_activity[]` retention rule). `hard` — no tombstone; the seller MUST NOT retain or echo the asset content elsewhere. `hard` is reserved for legal erasure or equivalent compelled destruction; sellers SHOULD default to `soft`.
   */
  purge_kind: 'soft' | 'hard';
  /**
   * ISO 8601 timestamp when the seller observed the destruction. Distinct from `fired_at`.
   * @format date-time
   */
  purged_at: string;
  reason_code: CreativeEventReasonCode;
  /**
   * Human-readable supplement. Sellers MUST NOT include third-party PII or the asset content in this field — the field is meant for operational context, not asset preservation.
   * @maxLength 500
   */
  reason_detail?: string;
  /**
   * Who initiated the purge. `seller` — explicit decision (legal team, content policy, takedown handler). `system` — automated retention sweep, storage policy enforcement. `buyer` never appears on this event — buyer-initiated destruction (if and when supported) is acknowledged on the `sync_creatives` response path.
   */
  initiator: 'seller' | 'system';
  ext?: ExtensionObject;
}

// creative/creative-status-changed-webhook.json
/**
 * Account-level push notification fired when a creative in the library transitions status by seller or system initiative. Fires per registered subscriber against each `notification_configs[]` entry whose `event_types` includes `creative.status_changed`. Buyer-initiated transitions (archive, unarchive, resubmit) do NOT fire — those are acknowledged on the `sync_creatives` response path. Receivers MUST verify signing per the registered scheme (RFC 9421 webhook profile by default; legacy Bearer / HMAC-SHA256 when `authentication` was supplied at registration) and dedupe by `idempotency_key`. See docs/protocol/snapshot-and-log.mdx for the snapshot/log duality rules — the current status is always authoritative on `list_creatives`.
 */
export interface CreativeStatusChangedWebhook {
  /**
   * Sender-generated key stable across retries of the same fire. Sellers MUST generate a cryptographically random value (UUID v4 recommended) per distinct fire and reuse it on every retry of the same fire. Receivers MUST dedupe by this key, scoped to the authenticated sender identity. Distinct from `notification_id` — same `notification_id` under two different `idempotency_key` values is a re-emission signal (snapshot-and-log Rule 1).
   * @minLength 16
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{16,255}$
   */
  idempotency_key: string;
  /**
   * Stable identifier for this logical transition event, used by buyers to correlate fires to current snapshot state. Stable across re-emissions of the same transition (e.g., the seller re-fires after the buyer's endpoint was unreachable); a fresh transition on the same creative receives a new id. Charset matches `idempotency_key` so the value is safe to log, embed in dashboard URLs, and pass into LLM prompts without escaping.
   * @minLength 1
   * @maxLength 255
   * @pattern ^[A-Za-z0-9_.:-]{1,255}$
   */
  notification_id: string;
  /**
   * Fixed notification type discriminator. Matches the value registered on the subscriber's `event_types`.
   */
  notification_type: 'creative.status_changed';
  /**
   * ISO 8601 timestamp when the seller initiated this fire. Distinct from when the transition was observed (`transition.observed_at`) — fires MAY be coalesced or delayed up to the seller's declared coalescence window for `creative.status_changed`.
   * @format date-time
   */
  fired_at: string;
  /**
   * Identifies which `notification_configs[]` entry on the recipient account is receiving this fire. Echoed verbatim from the entry's `subscriber_id`. Required so multi-subscriber accounts can route by endpoint.
   * @minLength 1
   * @maxLength 64
   * @pattern ^[A-Za-z0-9_.:-]{1,64}$
   */
  subscriber_id: string;
  /**
   * Seller's identifier for the account this creative belongs to. Echoed so multi-account buyers can route without re-resolving via `list_accounts`.
   */
  account_id: string;
  /**
   * Seller's identifier for the creative whose status changed. References the same id space as `list_creatives` / `sync_creatives` responses.
   */
  creative_id: string;
  /**
   * The status transition that triggered this fire. Valid `from` values are restricted to the prior states from which a seller/system-initiated transition can fire (`processing` for processing outcomes, `pending_review` for initial review outcomes, `approved` for re-review/revocation/seller-archive). The post-terminal states `rejected` and `archived` MUST NOT appear as `from` — those would require a buyer-initiated unblock (`sync_creatives` resubmit / unarchive), which does not fire this event.
   */
  transition: {
    /**
     * Prior status — restricted to the states from which a seller/system-initiated transition can fire. For initial review outcomes the prior status is `pending_review`; for processing outcomes it is `processing`; for seller re-review, post-approval revocation, and seller-initiated archive it is `approved`.
     */
    from: 'processing' | 'pending_review' | 'approved';
    to: CreativeStatus;
    /**
     * ISO 8601 timestamp when the seller observed the transition. Distinct from `fired_at` — `fired_at` reflects when the webhook was emitted, which may lag `observed_at` by up to the seller's coalescence window. **Ordering with `media-buy.impairment`:** when a creative transition also causes a media-buy impairment (e.g., `approved → rejected` while assignments exist), the `creative.status_changed` and `impairment` fires are not ordered — buyers MUST NOT assume one arrives before the other. Reconcile via the snapshot (`list_creatives` and `get_media_buys`) when the two fires reference the same `creative_id`.
     * @format date-time
     */
    observed_at: string;
  };
  reason_code: CreativeEventReasonCode;
  /**
   * Human-readable supplement to `reason_code`. Free text from the seller. Sellers MUST NOT include third-party PII in this field.
   * @maxLength 500
   */
  reason_detail?: string;
  /**
   * Who initiated the transition. `seller` — explicit decision by the seller (human reviewer, policy operator, takedown handler). `system` — automated seller-side process (processing pipeline, retention sweep, inactivity scan). `buyer` never appears on this event — buyer-initiated transitions are acknowledged on the `sync_creatives` response path and MUST NOT fire `creative.status_changed`.
   */
  initiator: 'seller' | 'system';
  ext?: ExtensionObject;
}

// creative/video-brief.json
/**
 * Structured per-segment generation brief for generative video products (Veo / Sora / Runway-class). Each `segments[]` entry declares a timed prompt the synthesis pipeline turns into a continuous shot — `order`, `duration_ms`, `prompt`, optional `vo` (voiceover line) and `caption` (on-screen text). This is a *generation* brief, not a creative-direction storyboard: there is no camera direction, shot type, mood, or reference-asset attachment. Buyers wanting to direct camera, lighting, or reference-image conditioning attach a `reference-asset.json` with `purpose: "storyboard"` separately — that's the visual-direction surface; video-brief is the structured prompt the model receives. Renamed from earlier `scenes` to call the shape what it is (a brief, not a scene-level production document).
 */
export interface VideoBrief {
  /**
   * Ordered list of per-segment prompts that compose the generated video. The sum of `duration_ms` across segments should match the target video duration declared by the format declaration's `duration_ms_exact` / `duration_ms_range`.
   */
  segments: {
    /**
     * 1-indexed sequence position of this segment in the final video.
     * @minimum 1
     */
    order: number;
    /**
     * Duration of this segment in milliseconds.
     * @minimum 1
     */
    duration_ms: number;
    /**
     * Text prompt fed to the synthesis pipeline for this segment (subject, action, setting, mood). Renamed from earlier `description` to make explicit that this is a generation prompt — not a description-of-finished-content.
     */
    prompt: string;
    /**
     * Voiceover line for this segment (optional).
     */
    vo?: string;
    /**
     * On-screen caption text for this segment (optional).
     */
    caption?: string;
  }[];
}


